// modules/auth/lib/handlers/logout.ts
import { Response } from 'bun';
import { requireUser, invalidateSession } from '/lib/auth';

export async function logoutHandler(req: Request): Promise<Response> {
  const user = await requireUser(req);
  if (!user) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401 });
  }

  try {
    await invalidateSession(user.sessionId);
    return new Response(JSON.stringify({ message: 'Logged out successfully' }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Failed to log out' }), { status: 500 });
  }
}

